from datetime import date

from .settings import settings as default_settings


# Daily teacher cost cap. Zero currently means unlimited.
DEFAULT_DAILY_LLM_CAP = 50
_daily_llm_calls = {}


def _today_str():
    return date.today().isoformat()


def reset_cost_state():
    _daily_llm_calls.clear()


def mechanical_decision(children):
    actions = [str(item.get("action") or "hold") for item in children.values()]
    action = "exit" if "exit" in actions else "hold"
    return {"method": "mechanical", "action": action, "observations": len(children)}


def _call_teacher(children, settings, gateway):
    daily_cap = int(getattr(settings, "mesh_daily_llm_cap", DEFAULT_DAILY_LLM_CAP) or 0)
    today = _today_str()
    if daily_cap > 0 and _daily_llm_calls.get(today, 0) >= daily_cap:
        return None
    if pending_queue_depth(settings) / MAX_PENDING_QUEUE_DEPTH >= 0.8:
        return None
    response = gateway(children)
    if response is None:
        return None
    _daily_llm_calls[today] = _daily_llm_calls.get(today, 0) + 1
    decision = dict(response)
    decision["method"] = "teacher"
    return decision


def handle_trade_context(db, state, children, stage, gateway, settings=None):
    settings = settings or default_settings
    mechanical = mechanical_decision(children)
    teacher = _call_teacher(children, settings, gateway)

    if stage in {"bootstrap", "demoted"} and teacher is not None:
        final = teacher
    else:
        final = mechanical

    state["decision"] = final
    if stage in {"shadow", "graduated"} and teacher is not None:
        state["teacher_observation"] = teacher
    return final
